+        let schema = SchemaHash("abc123456789".to_owned());
+
+        // DB has 100, index has 1 — 99% drift, but threshold is 1.0 (100%)
+        let source = MockSource::new(100);
+        let lifecycle = MockLifecycle::healthy(1);
+
